import{_ as l,o as i,c as e,ag as t}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"1978年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1978年/核心总结.md","filePath":"01_letters/1978年/核心总结.md"}'),r={name:"01_letters/1978年/核心总结.md"};function o(n,a,h,s,u,d){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="_1978年巴菲特致股东的信核心总结" tabindex="-1">1978年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1978年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1978年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1978年伯克希尔完成了与多元化零售公司合并，对蓝筹印花持股提升到58%，开始合并报表，这一年保险行业处于周期景气顶端，巴菲特整体回报率达到19.4%，非常出色。这封信最值得品味的是巴菲特对&quot;低价买少数股权&quot;的深入阐述，以及他为什么愿意被动持有优秀公司，不追求控制权的逻辑，这是他投资体系非常核心的一部分。文末可下载英文原版PDF。</p><h2 id="一、整体业绩" tabindex="-1">一、整体业绩 <a class="header-anchor" href="#一、整体业绩" aria-label="Permalink to &quot;一、整体业绩&quot;">​</a></h2><ul><li>1978年营业回报率（期初股权）19.4%，接近1972年的历史记录。过去三年（1976-1978）每股净资产几乎翻倍，年复利约25%，来自营业收益加资本利得。</li><li>保险周期已经向下掉头，1979年净资产回报率一定会下降，但由于股本扩大，美元计价的营业收益绝对值可能上升。对长期股权投资依然非常乐观。</li></ul><h2 id="二、各业务板块" tabindex="-1">二、各业务板块 <a class="header-anchor" href="#二、各业务板块" aria-label="Permalink to &quot;二、各业务板块&quot;">​</a></h2><h3 id="_1-纺织业务-依然低回报-但坚持继续做" tabindex="-1">1. 纺织业务：依然低回报，但坚持继续做 <a class="header-anchor" href="#_1-纺织业务-依然低回报-但坚持继续做" aria-label="Permalink to &quot;1. 纺织业务：依然低回报，但坚持继续做&quot;">​</a></h3><ul><li>1978年盈利130万美元，比去年改善，但1700万资本投入，回报率依然很低。</li><li>行业本质：纺织是资本密集型、产品同质化行业，只要产能过剩，价格只能反映直接运营成本，资本回报注定不行。</li><li>坚持原因还是老三条：当地重要雇主、管理层一直积极解决问题、劳工配合、预期能维持温和现金回报。</li></ul><h3 id="_2-保险承保-行业景气-整体出色-局部有好有坏" tabindex="-1">2. 保险承保：行业景气，整体出色，局部有好有坏 <a class="header-anchor" href="#_2-保险承保-行业景气-整体出色-局部有好有坏" aria-label="Permalink to &quot;2. 保险承保：行业景气，整体出色，局部有好有坏&quot;">​</a></h3><ul><li>菲尔·利切管理的国家赔偿业务，9000万保费赚1100万承保利润，非凡业绩。</li><li>塞浦路斯工人补偿公司第一年运营就非常出色，加州工人补偿业务正在整顿，业务收缩但进展不错。</li><li>本土公司业务整体令人失望，但堪萨斯公司新开第一年就损失率最低，是亮点。</li><li><strong>关键判断</strong>：1979年行业综合成本率一定会上升，因为费率涨幅赶不上成本（医疗维修涨9%，费率只涨3%），1979年全行业可能陷入承保亏损。</li></ul><h3 id="_3-保险投资-这是这封信的精华" tabindex="-1">3. 保险投资：这是这封信的精华 <a class="header-anchor" href="#_3-保险投资-这是这封信的精华" aria-label="Permalink to &quot;3. 保险投资：这是这封信的精华&quot;">​</a></h3><ul><li>巴菲特的买入条件，还是这四条，从未变过： <ol><li>企业我们能理解</li><li>长期前景良好</li><li>诚实能干的管理层</li><li>价格非常吸引人</li></ol></li><li>对比1971和1978年机构行为：1971年养老金把122%的净资金投股市（高位疯狂），1974年跌到只剩21%（低位恐惧），1978年更是只有9%，创了新低——这就是市场无效性来源。</li><li>伯克希尔自己：1975年底股权市值3930万（等于成本），1978年底成本1.291亿，市值2.165亿，三年累计已实现+未实现收益1.12亿，同期道琼斯还下跌了——这就是价值投资在熊市末期的美妙。</li><li>核心洞察：二级市场上，优秀企业的少数股权，往往比并购市场上平庸企业卖得还便宜很多。市场短期内不认可我们买的便宜货没关系，我们正好可以继续低价买，长期更有利。</li><li><strong>政策是集中持仓</strong>：不感兴趣的不买，真看好就买够量。</li><li>经典案例：SAFEO保险公司，巴菲特认为它是美国运营最好的大型财险公司，承保超棒，准备金保守，投资合理，我们买价大幅低于净资产。&quot;我们花不到1美元买1美元最好公司的股权，而并购市场平庸公司都要花超过1美元&quot;。</li><li>为什么不追求控制权？&quot;记录表明它们管理自己比我们管好，为什么要去干预？坐着让能人干就行了，少点兴奋和声望，但多赚钱。&quot;</li><li>关于留存收益：我们不介意被投资公司留存盈利，只要它们能以高回报率再投资，留存收益最终对我们的价值不比分掉差，甚至可能更高。这个增值不体现在当期我们的营业利润里，但长期真实存在。</li></ul><h3 id="_4-银行业-依旧出色-被迫要分拆" tabindex="-1">4. 银行业：依旧出色，被迫要分拆 <a class="header-anchor" href="#_4-银行业-依旧出色-被迫要分拆" aria-label="Permalink to &quot;4. 银行业：依旧出色，被迫要分拆&quot;">​</a></h3><ul><li>伊利诺伊国民银行ROA是大银行三倍，风险还更低，创始人吉恩·阿贝格81岁依然成本控制能力一流。</li><li>法令要求必须在1980年底前剥离，计划1980年下半年分拆给股东。</li></ul><h3 id="_5-零售-小而美-老而弥坚" tabindex="-1">5. 零售：小而美，老而弥坚 <a class="header-anchor" href="#_5-零售-小而美-老而弥坚" aria-label="Permalink to &quot;5. 零售：小而美，老而弥坚&quot;">​</a></h3><ul><li>合并获得联合零售，75家女装店，业务不增长，环境不利，但创始人本·罗斯纳75岁依然每天上班，成本控制极强，税后ROE常年20%。巴菲特非常欣赏这种能干到老、始终像所有者一样思考的经理人。</li></ul><h2 id="三、核心启示" tabindex="-1">三、核心启示 <a class="header-anchor" href="#三、核心启示" aria-label="Permalink to &quot;三、核心启示&quot;">​</a></h2><ol><li><strong>别人恐惧我贪婪</strong>：1970年代末机构对股市极度悲观，正好给了巴菲特低价大量买优秀企业的机会，三年赚了一倍多，道琼斯还跌了。</li><li><strong>不控股权也能赚大钱</strong>：没必要一定要控股才能赚钱，找到比你管得好的公司，低价买进去坐着享受，结果比你自己控股更好。</li><li><strong>集中持股</strong>：对将信将疑的不碰，真看好就下重手。</li><li><strong>理解留存收益的价值</strong>：优秀公司的留存收益能创造更大价值，不体现在当期股息，但长期会反映在市值上。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201978.pdf">巴菲特1978年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',20)])])}const q=l(r,[["render",o]]);export{c as __pageData,q as default};
